mapper.select:
select N.SHIKYUBI as shikyubi , N.NYURYOKU_KBN as nyuryokuKbnCd , N.KYUYO_KBN as kyuyoKbnCd , N.KYUYO_KASHO_CD as kyuyoKashoCd , N.KAMOKU_BUNRUI_CD as kamokuBunruiCd , N.KAMOKU_KBN_CD as kamokuKbnCd , N.GYOSHU_CD as gyoshuCd , N.SHOZOKU_CD as shozokuCd , N.KOSHINSHA as koshinsha , N.KOSHINBI as koshinbi , N.SHIHARASAKI_KBN as shiharaisakiKbn , N.SHIHARASAKI_CD as shiharaisakiCd , N.SHIHARAI_YOTEBI as shiharaiYoteibi from DAC213_JINKENHI_JOHO_NYURYOKU N where N.SAKZYO_KBN = '${SAKZYO_KBN_YUKO}' and N.SHIKYUBI = #{shikyubi} and N.NYURYOKU_KBN = #{listDetailNyuryokuKbnCd}
and N.NYURYOKU_KBN = #{nyuryokuKbnCd}
and N.KYUYO_KBN = #{kyuyoKbnCd}
and N.KYUYO_KASHO_CD = #{kyuyoKashoCd}
and N.KAMOKU_BUNRUI_CD = #{kamokuBunruiCd}
and N.KAMOKU_KBN_CD = #{kamokuKbnCd}
and N.GYOSHU_CD = #{gyoshuCd}
and N.SHOZOKU_CD = #{shozokuCd}
order by N.NYURYOKU_KBN asc , N.KYUYO_KBN asc , N.KYUYO_KASHO_CD asc , N.KAMOKU_BUNRUI_CD asc , N.KAMOKU_KBN_CD asc , N.GYOSHU_CD asc , N.SHOZOKU_CD asc

mapper.update:
update DAA301_JINKENHI_RENDO_JOHO_HEADER
set
    LSTUPD_DTM               = CURRENT TIMESTAMP
  , LSTUPD_USER_ID           = #{lstupdUserId}
  , HAITA_CNT                = #{haitaCnt}
  , SHONINJO_KBN             = #{shoninJokyoKbn}
  , NYURYOKU_USER_ID         = #{nyuryokuUserId}
  , TENPU_FILE_ID_1          = #{tenpuFileId1}
  , TENPU_FILE_ID_2          = #{tenpuFileId2}
  , TENPU_FILE_ID_3          = #{tenpuFileId3}
  , SANSHO_URL               = #{sanshoUrl}
  , SHINSEI_NO               = #{shinseiNo}
  , SHINSEI_IRAISHA_USER_ID  = #{shoninIraishaUserId}
where
    DEMPYO_NO = #{dempyoNo}
    and HAITA_CNT = #{haitaCnt}
